  26 |         .filter-pill.active { border-color: var(--ai-accent); color: var(--ai-accent); background: rgba(217, 70, 239, 0.05); }
  27 |         .filter-checkbox-item { display: flex; align-items: center; gap: 10px; padding: 12px; border-bottom: 1px solid #222; cursor: pointer; }
  28 |         .filter-checkbox-item:last-child { border-bottom: none; }
  29 |         .filter-checkbox-item span { font-family: 'JetBrains Mono'; font-size: 12px; flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
