  49 |             --text-muted: #a1a1aa;
  50 |             --border: #27272a;
  51 |             --nav-height: 80px;
  52 |         }
  53 | 
  54 |         * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }
  55 |         
  56 |         body {
  57 |             margin: 0; padding: 0; height: 100vh;
  58 |             background-color: var(--bg); color: var(--text-main);
  59 |             font-family: 'Inter', sans-serif;
  60 |             display: flex; flex-direction: column;
  61 |             overflow: hidden;
  62 |         }
  63 | 
  64 |         .hidden { display: none !important; }
  65 |         .flex-between { display: flex; justify-content: space-between; align-items: center; }
  66 |         .flex-gap { display: flex; gap: 8px; }
  67 | 
  68 |         /* MAIN VIEW LAYOUT */
  69 |         .main-view {
  70 |             flex: 1; overflow-y: auto; padding: 20px;
  71 |             padding-top: calc(env(safe-area-inset-top, 0px) + 20px);
  72 |             padding-bottom: calc(var(--nav-height) + 40px);
  73 |             scrollbar-width: none;
  74 |             scroll-behavior: smooth;
  75 |             -webkit-overflow-scrolling: touch;
  76 |         }
  77 |         /* Safe space for the bottom navigation and FAB */
  78 |         .bottom-spacer {
  79 |             height: calc(var(--nav-height) + 100px);
  80 |             width: 100%;
  81 |             flex-shrink: 0;
  82 |         }
  83 |         .main-view::-webkit-scrollbar { display: none; }
  84 |         
  85 |         .tab-content { display: none; animation: fadeUp 0.2s ease-out; }
  86 |         .tab-content.active { display: block; }
  87 |         @keyframes fadeUp { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }
  88 | 
  89 |         .header { font-size: 24px; font-weight: 700; margin-bottom: 20px; display: flex; align-items: center; justify-content: space-between; flex-shrink: 0; }
  90 |         
  91 |         .card {
  92 |             background: var(--card-bg); border: 1px solid var(--border);
  93 |             border-radius: 16px; padding: 16px; margin-bottom: 16px;
  94 |         }
  95 | 
  96 |         /* BUTTONS */
  97 |         .btn {
  98 |             width: 100%; padding: 14px; border-radius: 12px; border: none;
  99 |             font-weight: 600; font-size: 15px; cursor: pointer;
 100 |             display: flex; align-items: center; justify-content: center; gap: 8px;
 101 |             color: white; transition: opacity 0.2s;
 102 |         }
 103 |         .btn:active { opacity: 0.7; }
 104 |         .btn-primary { background: var(--primary); }
 105 |         .btn-dev { background: var(--dev); color: black; }
 106 |         .btn-prod { background: var(--prod); }
 107 |         .btn-danger { background: var(--danger); }
 108 |         .btn-outline { background: transparent; border: 1px solid var(--border); color: var(--text-muted); }
 109 | 
 110 |         /* INPUTS */
 111 |         .input-group { margin-bottom: 16px; }
 112 |         .input-label { display: block; color: var(--text-muted); font-size: 11px; margin-bottom: 6px; text-transform: uppercase; letter-spacing: 0.5px; }
 113 |         .input-field {
 114 |             width: 100%; background: var(--input-bg); border: 1px solid var(--border);
 115 |             color: var(--text-main); padding: 12px; border-radius: 10px;
 116 |             font-family: 'JetBrains Mono', monospace; font-size: 13px;
 117 |         }
 118 |         .input-field:focus { outline: 2px solid var(--primary); border-color: transparent; }
 119 | 
 120 |         /* FILE LIST */
 121 |         .file-list { display: flex; flex-direction: column; gap: 0; }
 122 |         .file-item {
 123 |             display: flex; justify-content: space-between; align-items: center;
 124 |             padding: 12px; border-bottom: 1px solid var(--border);
 125 |         }
 126 |         .file-item:last-child { border-bottom: none; }
 127 |         
 128 |         /* VERSIONS / HISTORY */
 129 |         .version-item { position: relative; padding: 12px 0; border-bottom: 1px solid var(--border); }
 130 |         .version-item:last-child { border-bottom: none; }
 131 |         .v-header { display: flex; justify-content: space-between; align-items: flex-start; }
 132 |         .v-info strong { display: block; font-size: 14px; margin-bottom: 2px; }
 133 |         .v-info small { color: var(--text-muted); font-size: 11px; }
 134 |         .v-note {
 135 |             margin-top: 8px; background: rgba(255,255,255,0.05); 
 136 |             padding: 8px; border-radius: 6px; font-size: 11px; color: #ddd;
 137 |             border-left: 2px solid var(--primary); display: none; cursor: pointer;
 138 |         }
 139 |         .v-note.has-content { display: block; }
 140 | 
 141 |         /* INSPECTOR STYLES */
 142 |         .ins-row { padding: 8px 12px; border-bottom: 1px solid #1a1a1c; font-family: 'JetBrains Mono'; font-size: 11px; position: relative; animation: fadeUp 0.1s; display: flex; align-items: flex-start; }
 143 | .ins-row details summary::-webkit-details-marker { color: var(--ai-accent); margin-top: 3px; }
 144 | .ins-row details[open] summary { border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 4px; margin-bottom: 4px; }
 145 |         .ins-row:hover .ins-copy-btn { opacity: 1; }
 146 |         .ins-copy-btn { position: absolute; right: 8px; top: 8px; opacity: 0; background: #222; border: 1px solid #444; color: #888; padding: 2px 6px; border-radius: 4px; cursor: pointer; z-index: 10; }
 147 |         .ins-copy-btn:hover { color: white; border-color: var(--primary); }
 148 |         
 149 |         .ins-log-info { border-left: 3px solid var(--primary); }
 150 |         .ins-log-warn { border-left: 3px solid var(--dev); background: rgba(234, 179, 8, 0.05); }
 151 |         .ins-log-error { border-left: 3px solid var(--danger); background: rgba(239, 68, 68, 0.05); }
 152 |         
 153 |         .ins-net-grid { display: grid; grid-template-columns: 50px 45px 1fr 60px; gap: 8px; cursor: pointer; align-items: center; }
 154 |         .ins-net-details { background: #050505; margin: 8px -12px -8px -12px; padding: 12px; border-top: 1px solid #222; display: none; }
 155 |         .ins-net-details.open { display: block; }
 156 | 
 157 |         /* FLOATING HUD */
 158 |         #floating-console-btn {
 159 |             position: fixed; width: 44px; height: 44px; background: #222; border: 1px solid #444;
 160 |             border-radius: 50%; display: none; align-items: center; justify-content: center;
 161 |             z-index: 100000; box-shadow: 0 4px 15px rgba(0,0,0,0.5); cursor: move;
 162 |             touch-action: none; color: var(--ai-accent); font-size: 18px;
 163 |         }
 164 |         #floating-console-btn svg { width: 20px; height: 20px; pointer-events: none; }
 165 |         
 166 |         /* HALF SCREEN OVERRIDE */
 167 |         .inspector-half {
 168 |             top: auto !important; bottom: 0 !important; height: 60vh !important;
 169 |             border-top: 1px solid var(--border);
 170 |             transform: translateY(100%) !important;
 171 |             background: rgba(5, 5, 7, 0.85) !important;
 172 |             backdrop-filter: blur(15px) !important;
