 219 |             width: 160px; /* Slightly wider for descriptive text */
 220 |             z-index: 60; /* ADDED to ensure it's on top */
 221 |         }
 222 |         .log-header .menu-item {
 223 |             font-size: 11px;
 224 |             padding: 9px 12px;
 225 |         }
