 227 |         /* EDITOR STYLES (FULL SCREEN UPDATE) */
 228 |         .editor-toolbar {
 229 |             display: flex; justify-content: flex-start; align-items: center; 
 230 |             gap: 8px; margin-bottom: 8px; flex-shrink: 0; 
 231 |             overflow-x: auto; white-space: nowrap; scrollbar-width: none; -ms-overflow-style: none;
 232 |         }
 233 |         .editor-toolbar::-webkit-scrollbar { display: none; }
 234 |         .editor-toolbar span { flex-shrink: 0; }
 235 |         .icon-btn { flex-shrink: 0; background: var(--card-bg); border: 1px solid var(--border); color: var(--text-muted); padding: 6px 12px; border-radius: 8px; cursor: pointer; font-size: 12px; display: flex; align-items: center; gap: 5px; }
 236 |         .icon-btn:active { background: var(--border); }
 237 |         
 238 |         .json-editor {
 239 |             width: 100%; 
 240 |             background: var(--input-bg);
 241 |             border: 1px solid var(--border); color: #d4d4d4;
 242 |             font-family: 'JetBrains Mono', monospace; font-size: 13px; line-height: 1.5;
 243 |             padding: 12px; border-radius: 12px; resize: vertical; 
