 269 |         .log-header {
 270 |             padding: 12px; cursor: pointer; display: flex; align-items: center; justify-content: space-between;
 271 |             background: #151517; border-bottom: 1px solid transparent; transition: all 0.2s;
 272 |             border-left: 3px solid transparent; position: relative;
