 309 |             position: fixed; top: 0; left: 0; width: 100%; height: 100%;
 310 |             background: var(--bg); z-index: 200; display: flex; flex-direction: column;
 311 |             transform: translateX(100%); transition: transform 0.3s cubic-bezier(0.16, 1, 0.3, 1);
