 335 |         .url-bar:focus { border-color: var(--primary); }
 336 | 
 337 |         .preview-container {
 338 |             /* Calculated height: Viewport - Nav - Header - Padding */
 339 |             height: calc(100vh - 180px);
 340 |             border-radius: 12px; overflow: hidden; border: 1px solid var(--border);
 341 |             background: white; position: relative; margin-bottom: 10px;
 342 |         }
 343 |         iframe { width: 100%; height: 100%; border: none; }
 344 |         
 345 |         /* FULLSCREEN PREVIEW MODE */
 346 |         body.fs-mode .nav-bar, body.fs-mode .header, body.fs-mode .main-view > p, body.fs-mode .fs-hide { display: none !important; }
 347 |         body.fs-mode .main-view { padding: 0 !important; height: 100vh; width: 100vw; overflow: hidden; }
 348 |         body.fs-mode #tab-preview { display: block; height: 100%; }
 349 |         body.fs-mode .preview-container { height: 100% !important; border: none; border-radius: 0; margin: 0; }
 350 |         .fs-back-btn { display: none; position: fixed; top: 20px; left: 20px; z-index: 9999; background: rgba(0,0,0,0.8); color: white; border-radius: 50%; width: 44px; height: 44px; align-items: center; justify-content: center; border: 1px solid rgba(255,255,255,0.2); cursor: pointer; backdrop-filter: blur(4px); }
 351 |         body.fs-mode .fs-back-btn { display: flex; }
 352 | 
 353 |         /* NAVBAR */
 354 |         .nav-bar {
 355 |             position: fixed; bottom: 0; width: 100%; height: var(--nav-height);
 356 |             background: rgba(21, 21, 23, 0.9); backdrop-filter: blur(10px);
 357 |             border-top: 1px solid var(--border);
 358 |             display: flex; justify-content: space-around; align-items: center;
 359 |             padding-bottom: env(safe-area-inset-bottom, 15px); z-index: 100;
 360 |         }
 361 |         .nav-item {
 362 |             background: none; border: none; color: var(--text-muted);
 363 |             display: flex; flex-direction: column; align-items: center; gap: 4px;
 364 |             font-size: 10px; font-weight: 500; cursor: pointer;
 365 |         }
 366 |         .nav-item svg { width: 24px; height: 24px; }
 367 |         .nav-item.active { color: var(--primary); }
 368 | 
 369 |         /* EF MANAGER RESPONSIVE OVERRIDES */
 370 |         .ef-layout { display: flex; flex: 1; overflow: hidden; }
 371 |         .ef-sidebar { width: 220px; border-right: 1px solid var(--border); display: flex; flex-direction: column; background: #0a0a0a; flex-shrink: 0; }
 372 |         .ef-list { flex: 1; overflow-y: auto; padding: 8px; display: flex; flex-direction: column; gap: 4px; }
 373 |         
 374 |         @media (max-width: 768px) {
 375 |             .ef-layout { flex-direction: column; }
 376 |             .ef-sidebar { width: 100%; height: auto; border-right: none; border-bottom: 1px solid var(--border); }
 377 |             .ef-list { flex-direction: row; overflow-x: auto; overflow-y: hidden; white-space: nowrap; padding: 12px; height: 60px; }
 378 |             .ef-list-item { min-width: 120px; flex-shrink: 0; }
 379 |             .ef-stage { padding: 12px !important; }
 380 |             .ef-controls { padding: 12px !important; flex-direction: column; align-items: stretch !important; gap: 10px; }
