4898 |     function formatBytes(bytes) {
4899 |         if (!bytes) return '0 B';
4900 |         const k = 1024;
4901 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4902 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4903 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
