4906 |     function timeAgo(dateString) {
4907 |         const date = new Date(dateString);
4908 |         const now = new Date();
4909 |         const seconds = Math.floor((now - date) / 1000);
4910 |         if (seconds < 10) return 'just now';
4911 |         if (seconds < 60) return seconds + 's ago';
4912 |         const minutes = Math.floor(seconds / 60);
4913 |         if (minutes < 60) return minutes + 'm ago';
4914 |         const hours = Math.floor(minutes / 60);
4915 |         if (hours < 24) return hours + 'h ago';
4916 |         return date.toLocaleDateString();
4917 |     }
