5116 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5117 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5118 |         
5119 |         const navItems = document.querySelectorAll('.nav-item');
5120 |         switchTab(tabId, navItems[navIndex]);
5121 | 
5122 |         const scrollContainer = document.querySelector('.main-view');
5123 |         let retryCount = 0;
5124 |         const MAX_RETRIES = 5;
5125 | 
5126 |         const attemptNavigation = async () => {
5127 |             const element = document.querySelector(selector);
5128 |             
5129 |             if (element) {
5130 |                 console.log("[DeepJump] Element found. Scrolling...");
5131 |                 
5132 |                 // Wait for any tab transition animations
5133 |                 await new Promise(r => setTimeout(r, 300));
5134 | 
5135 |                 let offsetTop = 0;
5136 |                 let curr = element;
5137 |                 while (curr && curr !== scrollContainer) {
5138 |                     offsetTop += curr.offsetTop;
5139 |                     curr = curr.offsetParent;
5140 |                 }
5141 | 
5142 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5143 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5144 | 
5145 |                 // Visual Highlight
5146 |                 element.style.transition = 'all 0.5s ease';
5147 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5148 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5149 |                 setTimeout(() => {
5150 |                     element.style.backgroundColor = '';
5151 |                     element.style.boxShadow = '';
5152 |                 }, 3000);
5153 |                 
5154 |                 console.groupEnd();
5155 |                 return true;
5156 |             }
5157 | 
5158 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5159 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5160 |                 retryCount++;
5161 |                 showGlobalToast("🔍 Searching deeper...");
5162 |                 
5163 |                 await loadMoreFn(); 
5164 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5165 |                 return attemptNavigation();
5166 |             }
5167 | 
5168 |             console.error("[DeepJump] Failed: Element not found after retries.");
5169 |             showGlobalToast("Entry not found in recent history.", true);
5170 |             console.groupEnd();
5171 |             return false;
5172 |         };
5173 | 
5174 |         setTimeout(attemptNavigation, 100);
5175 |     }
