6467 |         checkboxes.forEach(cb => {
6468 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
6469 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
6470 |         });
6471 | 
6472 |         // The target is the first record older than our selection that isn't also being deleted
6473 |         let rollbackTarget = null;
