7223 |     function extractTableNames(sql) {
7224 |         if (!sql) return [];
7225 |         const tables = [];
7226 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7227 |         
7228 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7229 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7230 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7231 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7232 | 
7233 |         let match;
7234 |         while ((match = fromRegex.exec(sql)) !== null) {
7235 |             const name = match[1];
7236 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7237 |                 tables.push(name);
7238 |             }
7239 |         }
7240 |         
7241 |         while ((match = metaRegex.exec(sql)) !== null) {
7242 |             const name = match[1];
7243 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7244 |                 tables.push(name);
7245 |             }
7246 |         }
7247 | 
7248 |         return tables;
7249 |     }
7250 | 
7251 |     function convertToCSV(resultObj) {
7252 |         const data = resultObj.data || [];
7253 |         if (!data.length) return '';
7254 |         
7255 |         const tables = extractTableNames(resultObj.sql);
7256 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7257 | 
7258 |         const headers = Object.keys(data[0]);
7259 |         const rows = data.map(row => 
7260 |             headers.map(header => {
7261 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7262 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7263 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7264 |             }).join(',')
7265 |         );
7266 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7267 |     }
